SELECT (value->>'id')::text, value, now()
FROM jsonb_array_elements('[{"id":"brook-so20","name":"Brook","village":"Brook","town":"Winchester","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.10232,"lng":-1.47756},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Brook is a small SO20 settlement in the Stockbridge/Test Valley area, positioned within the same chalk-stream landscape that defines nearby villages like Broughton and Houghton. It is primarily residential-rural in function, with day-to-day service reliance on nearby centres rather than a large village core. The setting is attractive but practical life is shaped by road access to Stockbridge, Andover and Romsey.","character":"Small hamlet feel, scattered housing, quiet lanes, and countryside outlooks rather than high-street activity.","amenities":["Limited in-hamlet commercial offer","Nearby access to Stockbridge shops, medical services and eateries","Strong countryside walking/cycling environment"],"schools":[{"name":"Stockbridge Primary School","phase":"Primary","type":"State","ofsted":"Good (2023)","distance":"~3–5 miles (area dependent)","url":"https://reports.ofsted.gov.uk/provider/21/116028"},{"name":"Test Valley School","phase":"Secondary","type":"State","ofsted":"Good (2023)","distance":"~3–5 miles (area dependent)","url":"https://reports.ofsted.gov.uk/provider/23/116430"}],"transport":{"commutes":[{"to":"Winchester","mode":"Drive","typical":"~25–35 min","notes":"A30/A272 options"},{"to":"Southampton","mode":"Drive","typical":"~35–45 min","notes":"typically A3057/M27"},{"to":"London Waterloo","mode":"Train (from Andover/Winchester)","typical":"~1h10–1h30 rail + drive","notes":"no station in Brook"}]},"prices":{"summary":"SO20 transactions are typically led by detached and period village housing across the Test Valley.","average":"£557,054","detached":"£8